import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Plus } from 'lucide-react';
import FormularioOferta from './FormularioOferta';
import ListaOfertas from './ListaOfertas';

const GestionOfertas = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [mostrarForm, setMostrarForm] = useState(false);
  const [nombreLocal, setNombreLocal] = useState("Cargando...");

  // 1. CARGA DE OFERTAS: Específicas de este local mediante su ID
  const [ofertas, setOfertas] = useState(() => {
    const guardadas = localStorage.getItem(`ofertas-local-${id}`);
    return guardadas ? JSON.parse(guardadas) : [];
  });

  // 2. RECUPERAR NOMBRE DEL LOCAL: Busca en la lista de locales de Dashboard
  useEffect(() => {
    const localesGuardados = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const localEncontrado = localesGuardados.find(l => l.id.toString() === id.toString());
    if (localEncontrado) {
      setNombreLocal(localEncontrado.nombre);
    }
  }, [id]);

  // 3. PERSISTENCIA: Guarda las ofertas del local actual cada vez que cambian
  useEffect(() => {
    localStorage.setItem(`ofertas-local-${id}`, JSON.stringify(ofertas));
  }, [ofertas, id]);

  const agregarOferta = (nuevaOferta) => {
    const ofertaCompleta = { 
      id: Date.now(), 
      ...nuevaOferta,
      fechaCreacion: new Date().toLocaleDateString()
    };
    setOfertas([ofertaCompleta, ...ofertas]);
    setMostrarForm(false);
  };

  const eliminarOferta = (ofertaId) => {
    setOfertas(ofertas.filter(o => o.id !== ofertaId));
  };

  return (
    <div style={containerStyle}>
      <header style={headerStyle}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <button onClick={() => navigate('/dashboard')} style={btnVolver}>
            <ArrowLeft size={20} />
          </button>
          <div>
            <h1 style={{ margin: 0, fontSize: '1.5rem' }}>{nombreLocal}</h1>
            <span style={{ color: '#64748b', fontSize: '0.9rem' }}>Gestión de Inventario</span>
          </div>
        </div>
        
        <button onClick={() => setMostrarForm(true)} style={btnNuevaOferta}>
          <Plus size={18} /> Publicar Oferta
        </button>
      </header>

      <div style={contentLayout}>
        {mostrarForm ? (
          <FormularioOferta 
            onSave={agregarOferta} 
            onCancel={() => setMostrarForm(false)} 
          />
        ) : (
          <ListaOfertas 
            ofertas={ofertas} 
            onDelete={eliminarOferta} 
          />
        )}
      </div>
    </div>
  );
};

const containerStyle = { padding: '40px 5%', background: '#f8fafc', minHeight: '90vh' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const btnVolver = { background: 'white', border: '1px solid #e2e8f0', padding: '10px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center' };
const btnNuevaOferta = { background: '#e67e22', color: 'white', border: 'none', padding: '12px 20px', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const contentLayout = { maxWidth: '1000px', margin: '0 auto' };

export default GestionOfertas;
